import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(() => !!localStorage.getItem('token-falso'));
  const [userRole, setUserRole] = useState(() => localStorage.getItem('user-role')); 

  const cerrarSesion = () => {
    localStorage.clear();
    setIsLoggedIn(false);
    setUserRole(null);
    window.location.href = '/login'; 
  };

  return (
    <Router>
      <Header isLoggedIn={isLoggedIn} userRole={userRole} cerrarSesion={cerrarSesion} />
      <main style={{ minHeight: 'calc(100vh - 75px)' }}>
        <Routes>

          {/* EL HOME ahora es libre para que cualquiera lo vea */}
          <Route path="/" element={<Home />} />

          {/* LOGIN: Solo aquí hacemos la redirección automática al entrar */}
          <Route path="/login" element={
            isLoggedIn 
              ? (userRole === 'vendedor' ? <Navigate to="/dashboard" replace /> : <Navigate to="/" replace />) 
              : <Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />
          } />

          {/* PANEL DEL VENDEDOR: Protegido */}
          <Route path="/dashboard" element={
            isLoggedIn && userRole === 'vendedor' 
              ? <Dashboard /> 
              : <Navigate to="/login" replace />
          } />

          {/* GESTIÓN DE OFERTAS: Protegido */}
          <Route path="/ofertas/:id" element={
            isLoggedIn && userRole === 'vendedor' 
              ? <GestionOfertas /> 
              : <Navigate to="/login" replace />
          } />

          {/* CUALQUIER OTRA RUTA: Al Home */}
          <Route path="*" element={<Navigate to="/" replace />} />

        </Routes>
      </main>
    </Router>
  );
}

export default App;
